// Format the analysis result into a readable Zendesk internal note
const data = $input.first().json;
const result = data.result;

if (!result) {
  return [{ json: { note: 'Analysis completed but returned no result data.', analysis_id: data.analysis_id || 'unknown' } }];
}

const sev = { critical: '\u{1F534}', warning: '\u{1F7E1}', info: '\u{1F535}' };

let note = '## Automated Log Analysis Report\n\n';
note += '| Metric | Value |\n|---|---|\n';
note += `| Health Score | **${result.health_score.toFixed(1)}/100** (Grade: **${result.health_grade}**) |\n`;
note += `| Success Rate | ${result.success_rate.toFixed(1)}% |\n`;
note += `| Records Analyzed | ${result.total_records} |\n`;
note += `| Date Range | ${result.date_range} |\n`;
note += `| Log Type | ${result.log_type} |\n`;

if (result.trend) {
  note += `| Trend | ${result.trend.direction} (${result.trend.confidence} confidence) |\n`;
}

note += `\n### AI Summary\n${result.summary}\n\n`;

if (result.issues && result.issues.length > 0) {
  note += `### Issues Found (${result.issues.length})\n\n`;
  for (const issue of result.issues) {
    const icon = sev[issue.severity] || '\u26AA';
    note += `${icon} **${issue.severity.toUpperCase()}: ${issue.title}**\n`;
    note += `> ${issue.description}\n`;
    note += `> Affected records: ${issue.affected_records}\n`;
    note += `> Recommendation: ${issue.recommendation}\n\n`;
  }
}

if (result.chart_data && result.chart_data.error_distribution && result.chart_data.error_distribution.length > 0) {
  note += '### Top Errors\n\n';
  for (const e of result.chart_data.error_distribution.slice(0, 10)) {
    note += `- **${e.error}**: ${e.count} occurrences\n`;
  }
  note += '\n';
}

note += '---\n*Generated automatically by Plivo Log Analyser*';

return [{
  json: {
    note,
    analysis_id: data.analysis_id,
    health_score: result.health_score,
    health_grade: result.health_grade,
    success_rate: result.success_rate
  }
}];

// Format an error message for failed analyses
const data = $input.first().json;

const note = `## Log Analysis Failed\n\n`
  + `**Status:** ${data.status}\n`
  + `**Message:** ${data.message || 'Unknown error'}\n`
  + `**Analysis ID:** ${data.analysis_id || 'N/A'}\n\n`
  + `Please run the analysis manually at http://localhost:3000 or contact engineering.\n\n`
  + `---\n*Generated automatically by Plivo Log Analyser*`;

return [{
  json: {
    note,
    analysis_id: data.analysis_id || 'unknown'
  }
}];
